 ('4c31da68-acac-53e2-b651-3a6ed553df52','f229ce58-0374-5299-a675-d151d59803d1',2,$p$Passato → trapassato · futuro → condizionale composto$p$,$p$Passato → trapassato · futuro → condizionale composto$p$,'lesson',15),
 ('ef1520c4-3054-54e0-ac79-5c2553cace49','f229ce58-0374-5299-a675-d151d59803d1',3,$p$Preguntas indirectas (se/dove/cosa) + congiuntivo imperfetto$p$,$p$Preguntas indirectas (se/dove/cosa) + congiuntivo imperfetto$p$,'lesson',15),
 ('51e9f0c6-00cf-5791-98b2-07c9e0f688c4','f229ce58-0374-5299-a675-d151d59803d1',4,$p$Órdenes con «di + infinito» y cambio de deícticos$p$,$p$Órdenes con «di + infinito» y cambio de deícticos$p$,'lesson',15),
 ('767ee111-3759-5a3e-9fcd-56fa6af460b7','f229ce58-0374-5299-a675-d151d59803d1',5,$p$🏁 Checkpoint Unità 22$p$,$p$Transforma el discurso directo en indirecto con verbo principal en pasado aplicando la concordanza completa (presente→imperfetto, passato prossimo→trapassato, futuro→condizionale composto, congiuntivo presente→imperfetto), reformula preguntas indirectas (se/dove/cosa + congiuntivo imperfetto), da órdenes con «di + infinito» y adapta los deícticos (ora→allora, oggi→quel giorno, ieri→il giorno prima, domani→il giorno dopo, qui→lì, questo→quello).$p$,'checkpoint',40)
